export default function EcosystemMountain() {
  const router = useRouter()
  const [hovered, setHovered] = useState<string | null>(null)

  return (
    <PageSection ghost="SENSING WAVE">
      <div className="wrap">
        <PageTitle sub="Two Paths, One Mountain" title="兩個方向，一座山" />

        <svg
          viewBox="0 0 700 390"
          xmlns="http://www.w3.org/2000/svg"
          style={{ width: '100%', display: 'block', borderRadius: 12 }}
        >
          <image
            href="/index/森波生態系.png"
            x="0"
            y="0"
            width="700"
            height="390"
            preserveAspectRatio="xMidYMid slice"
          />

          {zones.map(zone => (
            <path
              key={zone.id}
              d={zone.d}
              fill={hovered === zone.id ? zone.hoverColor : 'transparent'}
              stroke="none"
              style={{ cursor: 'pointer', transition: 'fill 0.22s' }}
              onMouseEnter={() => setHovered(zone.id)}
              onMouseLeave={() => setHovered(null)}
              onClick={() => router.push(zone.href)}
            />
          ))}

          {zones.map(zone => (
            <g
              key={`tip-${zone.id}`}
              style={{
                opacity: hovered === zone.id ? 1 : 0,
                pointerEvents: 'none',
                transition: 'opacity 0.2s',
              }}
            >
              <rect
                x={zone.tipRectX}
                y={zone.tipRectY}
                width={zone.tipW}
                height={zone.tipH}
                rx="8"
                fill={zone.tipFill}
              />
              <text
                x={zone.tipX}
                y={zone.tipY}
                textAnchor="middle"
                fill="white"
                fontSize="12"
                fontWeight="500"
                fontFamily="sans-serif"
              >
                {zone.label}
              </text>
              <text
                x={zone.tipX}
                y={zone.tipY + 15}
                textAnchor="middle"
                fill="rgba(255,255,255,0.88)"
                fontSize="10"
                fontFamily="sans-serif"
              >
                {zone.sub1}
              </text>
              {zone.sub2 && (
                <text
                  x={zone.tipX}
                  y={zone.tipY + 28}
                  textAnchor="middle"
                  fill="rgba(255,255,255,0.88)"
                  fontSize="10"
                  fontFamily="sans-serif"
                >
                  {zone.sub2}
                </text>
              )}
            </g>
          ))}
        </svg>

        {/* Legend */}
        <div
          style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: '8px 20px',
            marginTop: 16,
            justifyContent: 'center',
          }}
        >
          {[
            { color: '#c8a000', text: 'AS · TS-PE　高階職業養成' },
            { color: '#5040b0', text: 'SC　薩滿靈魂覺醒' },
            { color: '#b03060', text: 'HL　深層系統對齊' },
            { color: '#9a5010', text: 'QI　即時洞察與梳理' },
          ].map(item => (
            <div
              key={item.color}
              style={{ display: 'flex', alignItems: 'center', gap: 6 }}
            >
              <span
                style={{
                  width: 10,
                  height: 10,
                  borderRadius: '50%',
                  background: item.color,
                  display: 'inline-block',
                  flexShrink: 0,
                }}
              />
              <span
                style={{
                  fontFamily: 'var(--f-mono)',
                  fontSize: 11,
                  color: 'var(--muted)',
                  letterSpacing: '0.04em',
                }}
              >
                {item.text}
              </span>
            </div>
          ))}
        </div>
      </div>
    </PageSection>
  )
}
